package com.sidney.banking.reconciliation;
import com.sidney.banking.account.*; import com.sidney.banking.ledger.LedgerRepository; import jakarta.persistence.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.math.BigDecimal; import java.time.Instant; import java.util.UUID;
@Service public class ReconciliationService {private final AccountRepository accounts;private final LedgerRepository ledger;@PersistenceContext EntityManager em;public ReconciliationService(AccountRepository a,LedgerRepository l){accounts=a;ledger=l;}@Transactional public void reconcileAll(){for(var a:accounts.findAll()){var expected=ledger.calculateBalance(a.getId()).setScale(2);var diff=a.getBalance().subtract(expected);em.persist(new Reconciliation(a.getId(),a.getBalance(),expected,diff));}}}
@Entity @Table(name="reconciliations") class Reconciliation{@Id UUID id;UUID accountId;BigDecimal accountBalance;BigDecimal ledgerBalance;BigDecimal difference;String status;Instant checkedAt;protected Reconciliation(){}Reconciliation(UUID a,BigDecimal b,BigDecimal l,BigDecimal d){id=UUID.randomUUID();accountId=a;accountBalance=b;ledgerBalance=l;difference=d;status=d.signum()==0?"MATCHED":"DIVERGENT";checkedAt=Instant.now();}}
